import{_ as a,o as i,c as r,ak as s}from"./chunks/framework.0gCUzwrR.js";const b=JSON.parse('{"title":"🧪 Ejercicio Práctico: Generación de dirección IPv6 de enlace local con SLAAC y EUI-64","description":"","frontmatter":{},"headers":[],"relativePath":"redes/ipv6/ejercicio1.md","filePath":"redes/ipv6/ejercicio1.md","lastUpdated":1775408517000}'),c={name:"redes/ipv6/ejercicio1.md"};function l(o,e,n,d,t,p){return i(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="🧪-ejercicio-practico-generacion-de-direccion-ipv6-de-enlace-local-con-slaac-y-eui-64" tabindex="-1">🧪 Ejercicio Práctico: Generación de dirección IPv6 de enlace local con SLAAC y EUI-64 <a class="header-anchor" href="#🧪-ejercicio-practico-generacion-de-direccion-ipv6-de-enlace-local-con-slaac-y-eui-64" aria-label="Permalink to “🧪 Ejercicio Práctico: Generación de dirección IPv6 de enlace local con SLAAC y EUI-64”">​</a></h1><h2 id="direccion-mac-de-ejemplo" tabindex="-1">Dirección MAC de ejemplo <a class="header-anchor" href="#direccion-mac-de-ejemplo" aria-label="Permalink to “Dirección MAC de ejemplo”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>58:8A:5A:2B:3C:4D</span></span></code></pre></div><hr><h2 id="🔧-paso-1-separar-en-dos-mitades" tabindex="-1">🔧 Paso 1: Separar en dos mitades <a class="header-anchor" href="#🔧-paso-1-separar-en-dos-mitades" aria-label="Permalink to “🔧 Paso 1: Separar en dos mitades”">​</a></h2><p>Dividimos la dirección MAC en dos partes de 3 bytes:</p><ul><li>Primera mitad: <code>58:8A:5A</code></li><li>Segunda mitad: <code>2B:3C:4D</code></li></ul><hr><h2 id="🔧-paso-2-insertar-ff-fe-en-el-medio" tabindex="-1">🔧 Paso 2: Insertar <code>FF:FE</code> en el medio <a class="header-anchor" href="#🔧-paso-2-insertar-ff-fe-en-el-medio" aria-label="Permalink to “🔧 Paso 2: Insertar FF:FE en el medio”">​</a></h2><p>Resultado:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>58:8A:5A:FF:FE:2B:3C:4D</span></span></code></pre></div><hr><h2 id="🔧-paso-3-invertir-el-bit-u-l-7o-bit-del-primer-byte" tabindex="-1">🔧 Paso 3: Invertir el bit U/L (7º bit del primer byte) <a class="header-anchor" href="#🔧-paso-3-invertir-el-bit-u-l-7o-bit-del-primer-byte" aria-label="Permalink to “🔧 Paso 3: Invertir el bit U/L (7º bit del primer byte)”">​</a></h2><ul><li>Primer byte original: <code>58</code> = <code>01011000</code> (binario)</li><li>Invertimos el <strong>7º bit</strong> (de izquierda a derecha, posición 2):<br><code>01011000</code> → <code>01011010</code> = <code>5A</code> (hex)</li></ul><p>Nueva secuencia EUI-64:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>5A:8A:5A:FF:FE:2B:3C:4D</span></span></code></pre></div><hr><h2 id="🛜-paso-4-anadir-prefijo-de-enlace-local-fe80-64" tabindex="-1">🛜 Paso 4: Añadir prefijo de enlace local (<code>fe80::/64</code>) <a class="header-anchor" href="#🛜-paso-4-anadir-prefijo-de-enlace-local-fe80-64" aria-label="Permalink to “🛜 Paso 4: Añadir prefijo de enlace local (fe80::/64)”">​</a></h2><p>Combinamos el prefijo con el identificador de interfaz EUI-64:</p><h3 id="✅-direccion-ipv6-de-enlace-local-final" tabindex="-1">✅ Dirección IPv6 de enlace local final: <a class="header-anchor" href="#✅-direccion-ipv6-de-enlace-local-final" aria-label="Permalink to “✅ Dirección IPv6 de enlace local final:”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fe80::5a8a:5aff:fe2b:3c4d</span></span></code></pre></div><hr><h2 id="🧠-notas-importantes" tabindex="-1">🧠 Notas importantes <a class="header-anchor" href="#🧠-notas-importantes" aria-label="Permalink to “🧠 Notas importantes”">​</a></h2><ul><li>Esta dirección es válida <strong>solo dentro del enlace local</strong>.</li><li>Se genera automáticamente con <strong>SLAAC + EUI-64</strong>, sin usar DHCPv6.</li><li>El bit U/L invertido indica que es una dirección <strong>localmente administrada</strong>.</li></ul><p>🌐 <a href="ejercicio1.pdf">Descargar Ejercicio PDF</a></p>',25)])])}const f=a(c,[["render",l]]);export{b as __pageData,f as default};
